var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"연료는 충분히 채웠다.","JPN":"燃料は十分溜まったぜ。","ENG":"We got enough fuel.","TWN":"燃料已經加滿了。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"여기 들어간 게 다 얼마람? 구형 포드라 그런지 연비도 더럽게 구리네.","JPN":"しかし、どんだけ燃料を消耗するんだこのポートは？　旧型は燃費の悪さがとんでもねえ。","ENG":"How much would this much Eternium cost? Older models have such terrible mileage.","TWN":"一共加了多少永恆之金？因為是老式的分離艙，燃油的需求可能會很大。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"다이빙 벨은 에너지효율 외에도 고질적인 문제가 몇 가지 있어.","JPN":"ダイビングベルには、エネルギー効率以外にも、いくつか問題点がある。","ENG":"Diving Bells have several persistent issues besides fuel efficiency.","TWN":"除去能源效率外，潛水鐘還存在幾個問題。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이터니움을 태워 에너지로 전환하는 시동 과정이 아주 요란하고 오래 걸린다는 거지.","JPN":"エタニウムを燃やしてエネルギーに転換するための所要時間とその過程で発生する強烈な騒音だ。","ENG":"The process of burning Eternium into energy is very loud and time-consuming.","TWN":"燃燒永恆之金並將其轉化為能量的啟動過程會產生很大的噪音，並且需要很長時間。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"시설 내부에 침식체들이 들끓는 상황이니, 다이빙 벨을 가동하면 놈들이 몰려들겠군.","JPN":"この施設には侵食体が密集している。ダイビングベルを稼働したら奴らをここに集めてしまうわけか。","ENG":"With all these C.O.s in the facility, they'll be swarming us once we get this up and running.","TWN":"設施內部到處都是侵蝕體，只要啟動潛水鐘，它們就會湧過來吧？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"산 넘어 산이네.","JPN":"次から次へと難問だらけだな。","ENG":"Give me a break.","TWN":"問題一個接一個啊。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"그럼 어떻게 해야 돼?","JPN":"じゃあ、どうすればいいんだ？","ENG":"Then what do we do?","TWN":"那該怎麼辦？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"우리가 다이빙 벨을 충전하는 동안 힉스가 의료동의 남은 이터니움을 태워서 침식체들의 주의를 끌 거야.","JPN":"私たちがダイビングベルをチャージしている間、ヒックスが医療棟に残っているエタニウムを燃やして侵食体の注意を引きつける。","ENG":"While we charge up the Diving Bell, Hicks will burn the remaining Eternium in the medical wing to draw away the C.O.s.","TWN":"我們給潛水鐘充能的時候，希克斯會點燃醫療大樓中剩餘的永恆之金，吸引侵蝕體的注意。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"준비가 끝나면 신호탄을 쏴서 합류하고, 함께 탈출하는 거지.","JPN":"そして、こちらの準備が終わったら信号弾を打ち上げ、合流して脱出する。","ENG":"Once the preparations are complete, we'll fire a signal to rendezvous and escape together.","TWN":"我們充能結束後，發射訊號彈，通知希克斯和我們一起撤離。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"그렇게 했다가 그 4종 놈까지 꼬이는 건 아니겠지?","JPN":"もしさっきの4種の化け物まで寄って来たらどうする？","ENG":"I hope this doesn't attract the Category 4's attention.","TWN":"這樣做的話，不會把那個4類侵蝕體也吸引過來吧？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이터는 이터니움 연소가 아닌 카운터의 능력에만 반응해.","JPN":"イーターが反応するのはカウンターの能力だけだ。エタニウムには反応しない。","ENG":"Eaters respond only to Counter abilities, not Eternium combustion.","TWN":"暴食只會對制裁者的能力做出反應。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"쉽진 않겠지만, 힉스가 능력만 쓰지 않으면 녀석의 주의를 끌 위험은 없어.","JPN":"簡単なことではないが、ヒックスが能力さえ発動しなければ、奴に気づかれることはないはずだ。","ENG":"It won't be easy, but as long as Hicks doesn't use her abilities, there shouldn't be any risk of attracting its attention.","TWN":"雖說不容易，但只要希克斯不使用她的能力，就不會有引起它注意的風險。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"걱정 마세요! 제가 죽는 한이 있어도 능력은 안 쓸게요!","JPN":"心配しないでください！　自分は死んでも能力は使いません！","ENG":"Don't worry! I won't use my abilities, even if I die!","TWN":"不用擔心！我就算死，也不會使用制裁者的能力！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"그럼, 충전을 시작한다.","JPN":"じゃあ、チャージを始めるぞ。","ENG":"All right, let's charge up this thing.","TWN":"好，那麼，開始充能吧。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"}]`);export{e as default};